import '../lib/form_decoder.dart';
import '../lib/form_encoder.dart';

void expectEqual(Object? actual, Object? expected) {
  if (actual != expected) {
    throw StateError('Expected $expected, got $actual');
  }
}

void main() {
  final external = decodeForm('query=red+blue&tag=a%2Bb');
  expectEqual(external['query'], 'red blue');
  expectEqual(external['tag'], 'a+b');

  final emitted = encodeForm(<String, String>{
    'query': 'two words',
    'literal': 'x+y',
  });
  expectEqual(emitted, 'query=two+words&literal=x%2By');
}
